diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 7bff13d59528..7b38a93b3c0c 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1849,6 +1849,48 @@ static Value *simplifyAndOrOfFCmps(const SimplifyQuery &Q, FCmpInst *LHS,
                  ? static_cast<Value *>(LHS)
                  : ConstantInt::getBool(LHS->getType(), !IsAnd);
   }
+  // Handle comparisons with constant operands:
+  // (fcmp olt X, C0) | (fcmp olt X, C1) where C0 < C1 --> fcmp olt X, C1
+  // (fcmp olt X, C0) & (fcmp olt X, C1) where C0 < C1 --> fcmp olt X, C0
+  // Similar for other relational predicates
+  if (LHS0 == RHS0) {
+    const APFloat *LHSC, *RHSC;
+    if (match(LHS1, m_APFloat(LHSC)) && match(RHS1, m_APFloat(RHSC))) {
+      // Check if predicates are compatible (same direction)
+      auto isLessThan = [](FCmpInst::Predicate P) {
+        return P == FCmpInst::FCMP_OLT || P == FCmpInst::FCMP_OLE ||
+               P == FCmpInst::FCMP_ULT || P == FCmpInst::FCMP_ULE;
+      };
+      auto isGreaterThan = [](FCmpInst::Predicate P) {
+        return P == FCmpInst::FCMP_OGT || P == FCmpInst::FCMP_OGE ||
+               P == FCmpInst::FCMP_UGT || P == FCmpInst::FCMP_UGE;
+      };
+      
+      bool BothLessThan = isLessThan(PredL) && isLessThan(PredR);
+      bool BothGreaterThan = isGreaterThan(PredL) && isGreaterThan(PredR);
+      
+      if ((BothLessThan || BothGreaterThan) && PredL == PredR) {
+        APFloat::cmpResult Cmp = LHSC->compare(*RHSC);
+        if (Cmp == APFloat::cmpEqual)
+          return LHS; // Same comparison, just return one
+        
+        // For OR: take the comparison with the larger range
+        // For AND: take the comparison with the smaller range
+        // For less-than: larger constant = larger range
+        // For greater-than: smaller constant = larger range
+        bool LHSDominates;
+        if (BothLessThan)
+          LHSDominates = (Cmp == APFloat::cmpGreaterThan); // LHS constant is larger
+        else // BothGreaterThan
+          LHSDominates = (Cmp == APFloat::cmpLessThan); // LHS constant is smaller
+        
+        if (IsAnd)
+          LHSDominates = !LHSDominates; // Swap for AND
+        
+        return LHSDominates ? LHS : RHS;
+      }
+    }
+  }

   return nullptr;
 }

